require\('dotenv'\).config\(\);
const { Pool } = require\('pg'\);
const pool = new Pool\({
  host: process.env.DB_HOST,
  port: parseInt\(process.env.DB_PORT || '5432'\),
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  ssl: { rejectUnauthorized: false },
  connectionTimeoutMillis: 8000,
}\);
console.log\('Connecting to:', process.env.DB_HOST\);
pool.query\('SELECT NOW\(\) as time, current_database\(\) as db, current_user as user'\)
  .then\(r => {
    console.log\('Connected successfully'\);
    console.log\('Time    :', r.rows[0].time\);
    console.log\('Database:', r.rows[0].db\);
    console.log\('User    :', r.rows[0].user\);
    return pool.query\(\\`SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' ORDER BY table_name\\`\);
  }\)
  .then\(r => {
    console.log\('Tables  :', r.rows.length ? r.rows.map\(x => x.table_name\).join\(', '\) : 'none found'\);
    pool.end\(\);
  }\)
  .catch\(err => {
    console.error\('Connection failed:', err.message\);
    pool.end\(\);
  }\);
")
